import { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

export default function CreatePickupRequest() {
const [locations, setLocations] = useState([]);
const [requests, setRequests] = useState([]);

const [search, setSearch] = useState("");
const [selectedLocation, setSelectedLocation] = useState(null);
const [priority, setPriority] = useState("Medium");
const [showDropdown, setShowDropdown] = useState(false);

const [expandedId, setExpandedId] = useState(null);

useEffect(() => {
getLocations();
getRequests();
}, []);

const getLocations = async () => {
try {
const response = await axios.get(Api.get_All_Locations);
setLocations(response.data);
} catch (error) {
console.log(error);
}
};

const getRequests = async () => {
try {
const supervisorId = localStorage.getItem("id");

  const response = await axios.get(Api.get_All_Emg_Req);

  const myRequests = response.data.filter(
    (item) => item.requestedBy?._id === supervisorId
  );

  setRequests(myRequests);
} catch (error) {
  console.log(error);
}


};

const filteredLocations = locations.filter((item) =>
item.location
.toLowerCase()
.includes(search.toLowerCase())
);

const handleSubmit = async () => {
try {
if (!selectedLocation) {
return alert("Please Select Location");
}

  const supervisorId =
    localStorage.getItem("id");

  await axios.post(
    Api.create_Emg_Req,
    {
      requestedBy: supervisorId,
      location: selectedLocation._id,
      priority,
    }
  );

  alert("Request Created Successfully");

  setSearch("");
  setSelectedLocation(null);
  setPriority("Medium");

  getRequests();
} catch (error) {
  console.log(error);
  alert("Failed To Create Request");
}


};

return ( <div className="min-h-screen bg-gradient-to-br from-green-50 to-gray-100 p-4">


  <div className="max-w-md mx-auto">

    <div className="mb-6">
      <p className="text-xs uppercase tracking-widest text-gray-500 font-bold">
        Garbage Pickup Vehicle
      </p>

      <h1 className="text-4xl font-extrabold text-green-900 mt-2">
        Emergency Pickup
      </h1>
    </div>

    <div className="bg-white rounded-3xl shadow-lg p-5 border">

      <h2 className="font-bold text-lg mb-4">
        📍 Pickup Location
      </h2>

      <div className="relative">

        <input
          type="text"
          value={search}
          placeholder="Search Location..."
          onChange={(e) => {
            setSearch(e.target.value);
            setShowDropdown(true);
          }}
          className="w-full border-2 border-gray-200 rounded-xl px-4 py-3 outline-none focus:border-green-600"
        />

        {showDropdown && (
          <div className="absolute z-50 bg-white border rounded-xl shadow-lg mt-2 w-full max-h-60 overflow-y-auto">

            {filteredLocations.map((loc) => (
              <div
                key={loc._id}
                onClick={() => {
                  setSelectedLocation(loc);
                  setSearch(loc.location);
                  setShowDropdown(false);
                }}
                className="px-4 py-3 hover:bg-green-100 cursor-pointer"
              >
                {loc.location}
              </div>
            ))}

          </div>
        )}
      </div>

      {selectedLocation && (
        <div className="mt-3 bg-green-50 border border-green-200 rounded-xl p-3">
          Selected :
          {" "}
          {selectedLocation.location}
        </div>
      )}

      <h2 className="font-bold mt-6 mb-4">
        🚨 Priority
      </h2>

      <div className="grid grid-cols-3 gap-2">

        {["Low", "Medium", "High"].map(
          (item) => (
            <button
              key={item}
              onClick={() =>
                setPriority(item)
              }
              className={`py-3 rounded-xl border font-semibold

              ${
                priority === item
                  ? "bg-green-700 text-white"
                  : "bg-white"
              }
              `}
            >
              {item}
            </button>
          )
        )}

      </div>

      <button
        onClick={handleSubmit}
        className="w-full mt-6 bg-green-800 text-white py-4 rounded-2xl font-bold"
      >
        Submit Request
      </button>

    </div>

    <div className="mt-8">

      <h2 className="text-2xl font-bold text-green-900 mb-4">
        My Requests
      </h2>

      {requests.map((req) => {

        const steps = [
          "Pending",
          "Accepted",
          "Scheduled",
          "Arrived",
          "Completed",
        ];

        const currentIndex =
          steps.indexOf(req.status);

        return (
          <div
            key={req._id}
            className="bg-white rounded-2xl shadow-lg border mb-4 overflow-hidden"
          >

            <div
              className="p-4 cursor-pointer flex justify-between items-center"
              onClick={() =>
                setExpandedId(
                  expandedId === req._id
                    ? null
                    : req._id
                )
              }
            >

              <div>

                <h3 className="font-bold">
                  {
                    req.location
                      ?.location
                  }
                </h3>

                <p className="text-sm text-gray-500">
                  Priority :
                  {" "}
                  {req.priority}
                </p>

              </div>

              <div className="flex gap-3 items-center">

                <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-xs font-bold">
                  {req.status}
                </span>

                <span>
                  {expandedId ===
                  req._id
                    ? "▲"
                    : "▼"}
                </span>

              </div>

            </div>

            {expandedId ===
              req._id && (

              <div className="px-6 pb-6">

                {steps.map(
                  (
                    step,
                    index
                  ) => (

                    <div
                      key={step}
                      className="flex"
                    >

                      <div className="flex flex-col items-center">

                        <div
                          className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold

                          ${
                            index <=
                            currentIndex
                              ? "bg-green-600 text-white"
                              : "bg-gray-200"
                          }
                          `}
                        >
                          {index <=
                          currentIndex
                            ? "✓"
                            : index + 1}
                        </div>

                        {index !==
                          steps.length -
                            1 && (
                          <div
                            className={`w-1 h-12

                            ${
                              index <
                              currentIndex
                                ? "bg-green-600"
                                : "bg-gray-300"
                            }
                            `}
                          />
                        )}

                      </div>

                      <div className="ml-4 pb-6">

                        <h4 className="font-semibold">
                          {step}
                        </h4>

                        {step ===
                          "Scheduled" &&
                          req.scheduledDate && (
                            <p className="text-xs text-gray-500">
                              {new Date(
                                req.scheduledDate
                              ).toLocaleString()}
                            </p>
                          )}

                      </div>

                    </div>

                  )
                )}

              </div>

            )}

          </div>
        );
      })}

    </div>

  </div>

</div>


);
}
